import { NextResponse } from 'next/server';
import { z } from 'zod';

import { getAgentAuditLogDelegate } from '@/features/ai/agent-runtime/store-delegates';
import type {
  AgentAuditLogRecordDto,
  AgentAuditLogRecordsResponse,
} from '@/shared/contracts/agent-runtime';
import { internalError } from '@/shared/errors/app-error';
import { apiHandlerWithParams } from '@/shared/lib/api/api-handler';
import {
  optionalIntegerQuerySchema,
  optionalTrimmedQueryString,
} from '@/shared/lib/api/query-schema';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

const DEBUG_CHATBOT = process.env['DEBUG_CHATBOT'] === 'true';
export const querySchema = z.object({
  stepId: optionalTrimmedQueryString(),
  limit: optionalIntegerQuerySchema(z.number().int().min(10).max(500)),
});

type AgentAuditRouteRecord = {
  id: string;
  runId: string | null;
  level: string;
  message: string;
  metadata?: unknown;
  createdAt: Date | string;
};

export const GET = apiHandlerWithParams<{ runId: string }>(
  async (_req, _ctx, params) => {
    const requestStart = Date.now();
    const agentAuditLog = getAgentAuditLogDelegate();
    if (!agentAuditLog) {
      throw internalError('Agent audit storage is unavailable.');
    }
    const { runId } = params;
    const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
    const stepId = query.stepId ?? null;
    const take = query.limit ?? 200;
    const audits = await agentAuditLog.findMany<AgentAuditRouteRecord>({
      where: { runId },
      orderBy: { createdAt: 'desc' },
      take,
    });
    const filtered = stepId
      ? audits.filter((audit: AgentAuditRouteRecord) => {
        const metadata = audit.metadata as {
          stepId?: string;
          failedStepId?: string;
          activeStepId?: string;
          steps?: Array<{ id?: string }>;
        } | null;
        if (
          metadata?.stepId === stepId ||
          metadata?.failedStepId === stepId ||
          metadata?.activeStepId === stepId
        ) {
          return true;
        }
        if (Array.isArray(metadata?.steps)) {
          return metadata.steps.some((step: { id?: string }) => step?.id === stepId);
        }
        return false;
      })
      : audits;
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Audits loaded', {
        service: 'agent-api',
        runId,
        count: filtered.length,
        durationMs: Date.now() - requestStart,
      });
    }
    const response: AgentAuditLogRecordsResponse = {
      audits: filtered.map(
        (audit: AgentAuditRouteRecord): AgentAuditLogRecordDto => ({
          ...audit,
          runId: audit.runId ?? null,
          metadata: audit.metadata ?? null,
          createdAt:
            audit.createdAt instanceof Date ? audit.createdAt.toISOString() : audit.createdAt,
        })
      ),
    };
    return NextResponse.json(response);
  },
  {
    source: 'chatbot.agent.[runId].audits.GET',
    requireAuth: true,
    querySchema,
  }
);

import { type NextRequest, NextResponse } from 'next/server';

import { runAgentBrowserControl } from '@/features/ai/agent-runtime/tools/run-agent-browser-control';
import { badRequestError, internalError } from '@/shared/errors/app-error';
import {
  apiHandlerWithParams,
  type ApiHandlerContext as _ApiHandlerContext,
} from '@/shared/lib/api/api-handler';
import { getChatbotAgentRunDelegate } from '@/features/ai/agent-runtime/store-delegates';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const DEBUG_CHATBOT = process.env['DEBUG_CHATBOT'] === 'true';

async function postHandler(
  req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  if (!getChatbotAgentRunDelegate()) {
    throw internalError('Agent run storage is unavailable.');
  }
  const { runId } = await params;
  let body: {
    action?: string;
    url?: string;
    stepId?: string;
    stepLabel?: string;
  };
  try {
    body = (await req.json()) as typeof body;
  } catch (error) {
    logClientError(error);
    throw badRequestError('Invalid JSON payload');
  }
  const action = body.action as 'goto' | 'reload' | 'snapshot' | undefined;
  if (!action || !['goto', 'reload', 'snapshot'].includes(action)) {
    throw badRequestError('Invalid control action.');
  }
  if (action === 'goto' && !body.url?.trim()) {
    throw badRequestError('URL is required for goto action.');
  }

  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Control request', {
      service: 'agent-api',
      runId,
      action,
      url: body.url?.trim(),
    });
  }

  const result = await runAgentBrowserControl({
    runId,
    action,
    url: body.url,
    stepId: body.stepId,
    stepLabel: body.stepLabel,
  });

  if (!result.ok) {
    throw internalError(result.error || 'Control action failed.', {
      controlErrorId: result.errorId,
    });
  }

  return NextResponse.json({ ok: true, output: result.output });
}

export const POST = apiHandlerWithParams<{ runId: string }>(
  async (req: NextRequest, _ctx, params) => postHandler(req, { params: Promise.resolve(params) }),
  { source: 'chatbot.agent.[runId].controls.POST', requireAuth: true }
);

import { promises as fs } from 'fs';
import path from 'path';

import { type NextRequest, NextResponse } from 'next/server';

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import {
  type AgentRuntimeRunRecord,
  getChatbotAgentRunDelegate,
} from '@/features/ai/agent-runtime/store-delegates';
import {
  badRequestError,
  conflictError,
  internalError,
  notFoundError,
} from '@/shared/errors/app-error';
import {
  apiHandlerWithParams,
  type ApiHandlerContext as _ApiHandlerContext,
} from '@/shared/lib/api/api-handler';
import type { InputJsonValue } from '@/shared/contracts/json';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const DEBUG_CHATBOT = process.env['DEBUG_CHATBOT'] === 'true';

type AgentRunRouteRecord = Pick<
  AgentRuntimeRunRecord,
  'id' | 'prompt' | 'status' | 'planState'
> & {
  checkpointedAt?: Date | string | null;
  createdAt?: Date | string | null;
  updatedAt?: Date | string | null;
  logLines?: string[];
};

type AgentRunStatusRecord = Pick<AgentRuntimeRunRecord, 'id' | 'status'>;

async function getHandler(
  _req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const requestStart = Date.now();
  const chatbotAgentRun = getChatbotAgentRunDelegate();
  if (!chatbotAgentRun) {
    throw internalError('Agent run storage is unavailable.');
  }
  const { runId } = await params;
  const run = await chatbotAgentRun.findUnique<AgentRunRouteRecord>({
    where: { id: runId },
  });
  if (!run) {
    throw notFoundError('Run not found.');
  }
  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Run loaded', {
      service: 'agent-api',
      runId,
      status: run.status,
      durationMs: Date.now() - requestStart,
    });
  }
  return NextResponse.json({ run });
}

async function postHandler(
  req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const requestStart = Date.now();
  const chatbotAgentRun = getChatbotAgentRunDelegate();
  if (!chatbotAgentRun) {
    throw internalError('Agent run storage is unavailable.');
  }
  const { runId } = await params;
  let body: {
    action?: string;
    stepId?: string;
    status?: 'completed' | 'failed' | 'pending';
    prompt?: string;
  };

  try {
    body = (await req.json()) as typeof body;
  } catch (error) {
    logClientError(error);
    throw badRequestError('Invalid JSON payload');
  }
  if (
    !body.action ||
    !['stop', 'resume', 'retry_step', 'override_step', 'approve_step'].includes(body.action)
  ) {
    throw badRequestError('Unsupported action.');
  }
  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Request', {
      service: 'agent-api',
      runId,
      action: body.action,
    });
  }

  const run = await chatbotAgentRun.findUnique<AgentRunRouteRecord>({
    where: { id: runId },
  });

  if (!run) {
    throw notFoundError('Run not found.');
  }

  if (body.action === 'resume') {
    if (run.status === 'running') {
      return NextResponse.json({ status: run.status });
    }
    const nextPrompt =
      typeof body.prompt === 'string' && body.prompt.trim() ? body.prompt.trim() : null;
    const resumeStepId =
      typeof body.stepId === 'string' && body.stepId.trim() ? body.stepId.trim() : null;
    const resumePlanState =
      run.planState && typeof run.planState === 'object'
        ? {
          ...(run.planState as Record<string, unknown>),
          resumeRequestedAt: new Date().toISOString(),
          ...(nextPrompt ? { promptUpdatedAt: new Date().toISOString() } : {}),
          ...(resumeStepId ? { activeStepId: resumeStepId } : {}),
        }
        : {
          resumeRequestedAt: new Date().toISOString(),
          ...(nextPrompt ? { promptUpdatedAt: new Date().toISOString() } : {}),
          ...(resumeStepId ? { activeStepId: resumeStepId } : {}),
        };
    const updated = await chatbotAgentRun.update<AgentRunStatusRecord>({
      where: { id: runId },
      data: {
        status: 'queued',
        requiresHumanIntervention: false,
        errorMessage: null,
        finishedAt: null,
        checkpointedAt: new Date(),
        planState: resumePlanState,
        ...(resumeStepId ? { activeStepId: resumeStepId } : {}),
        ...(nextPrompt ? { prompt: nextPrompt } : {}),
        logLines: {
          push: `[${new Date().toISOString()}] Run resume requested.`,
        },
      },
    });
    if (nextPrompt && nextPrompt !== run.prompt) {
      await logAgentAudit(updated.id, 'warning', 'Agent prompt updated.', {
        promptLength: nextPrompt.length,
      });
    }
    await logAgentAudit(updated.id, 'info', 'Agent run resume requested.');
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Resumed', {
        service: 'agent-api',
        runId,
        status: updated.status,
        durationMs: Date.now() - requestStart,
      });
    }
    return NextResponse.json({ status: updated.status });
  }

  if (body.action === 'retry_step') {
    if (run.status === 'running') {
      throw conflictError('Run is running. Stop it before retrying steps.');
    }
    if (!body.stepId?.trim()) {
      throw badRequestError('stepId is required for retry_step.');
    }
    const planState =
      run.planState && typeof run.planState === 'object'
        ? (run.planState as Record<string, unknown>)
        : null;
    const steps = Array.isArray(planState?.['steps'])
      ? (planState?.['steps'] as Array<Record<string, unknown>>)
      : null;
    if (!steps) {
      throw badRequestError('No plan steps available to retry.');
    }
    const nextSteps = steps.map((step) => {
      if (step && typeof step === 'object' && step['id'] === body.stepId) {
        const typed = step as {
          id: string;
          status?: string;
          attempts?: number;
          maxAttempts?: number;
        };
        return {
          ...typed,
          status: 'pending',
          attempts: 0,
          maxAttempts: (typed['maxAttempts'] ?? 1) + 1,
        };
      }
      return step;
    });
    const now = new Date().toISOString();
    const nextPlanState = {
      ...(planState ?? {}),
      steps: nextSteps,
      activeStepId: body.stepId,
      resumeRequestedAt: now,
      updatedAt: now,
    };
    const updated = await chatbotAgentRun.update<AgentRunStatusRecord>({
      where: { id: runId },
      data: {
        status: 'queued',
        requiresHumanIntervention: false,
        errorMessage: null,
        finishedAt: null,
        checkpointedAt: new Date(),
        planState: nextPlanState as InputJsonValue,
        activeStepId: body.stepId,
        logLines: {
          push: `[${new Date().toISOString()}] Step retry requested (${body.stepId}).`,
        },
      },
    });
    await logAgentAudit(updated.id, 'warning', 'Step retry requested.', {
      stepId: body.stepId,
    });
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Step retry queued', {
        service: 'agent-api',
        runId,
        stepId: body.stepId,
        durationMs: Date.now() - requestStart,
      });
    }
    return NextResponse.json({ status: updated.status });
  }

  if (body.action === 'override_step') {
    if (run.status === 'running') {
      throw conflictError('Run is running. Stop it before overriding steps.');
    }
    if (!body.stepId?.trim() || !body.status) {
      throw badRequestError('stepId and status are required for override_step.');
    }
    const planState =
      run.planState && typeof run.planState === 'object'
        ? (run.planState as Record<string, unknown>)
        : null;
    const steps = Array.isArray(planState?.['steps'])
      ? (planState?.['steps'] as Array<Record<string, unknown>>)
      : null;
    if (!steps) {
      throw badRequestError('No plan steps available to override.');
    }
    const nextSteps = steps.map((step) => {
      if (step && typeof step === 'object' && step['id'] === body.stepId) {
        return { ...step, status: body.status };
      }
      return step;
    });
    const nextActive =
      body.status === 'completed'
        ? ((
            nextSteps.find(
              (step) =>
                step &&
                typeof step === 'object' &&
                (step as { status?: string }).status !== 'completed'
            ) as { id?: string } | undefined
        )?.id ?? null)
        : body.stepId;
    const now = new Date().toISOString();
    const nextPlanState = {
      ...(planState ?? {}),
      steps: nextSteps,
      activeStepId: nextActive,
      updatedAt: now,
    };
    const updated = await chatbotAgentRun.update<AgentRunStatusRecord>({
      where: { id: runId },
      data: {
        planState: nextPlanState as InputJsonValue,
        activeStepId: nextActive,
        checkpointedAt: new Date(),
        logLines: {
          push: `[${new Date().toISOString()}] Step overridden (${body.stepId} -> ${body.status}).`,
        },
      },
    });
    await logAgentAudit(updated.id, 'warning', 'Step overridden.', {
      stepId: body.stepId,
      status: body.status,
    });
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Step overridden', {
        service: 'agent-api',
        runId,
        stepId: body.stepId,
        status: body.status,
        durationMs: Date.now() - requestStart,
      });
    }
    return NextResponse.json({ status: updated.status });
  }

  if (body.action === 'approve_step') {
    if (run.status === 'running') {
      throw conflictError('Run is running. Stop it before approving steps.');
    }
    if (!body.stepId?.trim()) {
      throw badRequestError('stepId is required for approve_step.');
    }
    const planState =
      run.planState && typeof run.planState === 'object'
        ? (run.planState as Record<string, unknown>)
        : null;
    const now = new Date().toISOString();
    const updated = await chatbotAgentRun.update<AgentRunStatusRecord>({
      where: { id: runId },
      data: {
        status: 'queued',
        requiresHumanIntervention: false,
        errorMessage: null,
        finishedAt: null,
        checkpointedAt: new Date(),
        planState: {
          ...(planState ?? {}),
          approvalRequestedStepId: null,
          approvalGrantedStepId: body.stepId.trim(),
          activeStepId: body.stepId.trim(),
          updatedAt: now,
        },
        activeStepId: body.stepId.trim(),
        logLines: {
          push: `[${new Date().toISOString()}] Step approval granted (${body.stepId}).`,
        },
      },
    });
    await logAgentAudit(updated.id, 'warning', 'Step approval granted.', {
      stepId: body.stepId.trim(),
    });
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Step approved', {
        service: 'agent-api',
        runId,
        stepId: body.stepId.trim(),
        durationMs: Date.now() - requestStart,
      });
    }
    return NextResponse.json({ status: updated.status });
  }

  if (run.status === 'completed' || run.status === 'failed' || run.status === 'stopped') {
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logInfo('Already terminal', {
        service: 'agent-api',
        runId,
        status: run.status,
        durationMs: Date.now() - requestStart,
      });
    }
    return NextResponse.json({ status: run.status });
  }

  const updated = await chatbotAgentRun.update<AgentRunStatusRecord>({
    where: { id: runId },
    data: {
      status: 'stopped',
      finishedAt: new Date(),
      logLines: {
        push: `[${new Date().toISOString()}] Run stopped by user.`,
      },
    },
  });
  await logAgentAudit(updated.id, 'warning', 'Agent run stopped by user.');

  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Stopped', {
      service: 'agent-api',
      runId,
      status: updated.status,
      durationMs: Date.now() - requestStart,
    });
  }

  return NextResponse.json({ status: updated.status });
}

async function deleteHandler(
  req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const requestStart = Date.now();
  const chatbotAgentRun = getChatbotAgentRunDelegate();
  if (!chatbotAgentRun) {
    throw internalError('Agent run storage is unavailable.');
  }
  const { runId } = await params;
  const run = await chatbotAgentRun.findUnique<Pick<AgentRuntimeRunRecord, 'status'>>({
    where: { id: runId },
  });
  if (!run) {
    throw notFoundError('Run not found.');
  }
  const url = new URL(req.url);
  const force = url.searchParams.get('force') === 'true';
  if (run.status === 'running' && !force) {
    throw conflictError('Run is running. Stop it before deleting.');
  }
  if (run.status === 'running' && force) {
    await chatbotAgentRun.update({
      where: { id: runId },
      data: { status: 'stopped', finishedAt: new Date() },
    });
  }
  await chatbotAgentRun.delete({ where: { id: runId } });
  const runDir = path.join(process.cwd(), 'tmp', 'chatbot-agent', runId);
  await fs.rm(runDir, { recursive: true, force: true });
  await logAgentAudit(runId, 'warning', 'Agent run deleted.', {
    deletedAt: new Date().toISOString(),
  });
  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Deleted', {
      service: 'agent-api',
      runId,
      durationMs: Date.now() - requestStart,
    });
  }
  return NextResponse.json({ deleted: true });
}

export const GET = apiHandlerWithParams<{ runId: string }>(
  async (req: NextRequest, _ctx, params) => getHandler(req, { params: Promise.resolve(params) }),
  { source: 'chatbot.agent.[runId].GET', requireAuth: true }
);
export const POST = apiHandlerWithParams<{ runId: string }>(
  async (req: NextRequest, _ctx, params) => postHandler(req, { params: Promise.resolve(params) }),
  { source: 'chatbot.agent.[runId].POST', requireAuth: true }
);
export const DELETE = apiHandlerWithParams<{ runId: string }>(
  async (req: NextRequest, _ctx, params) =>
    deleteHandler(req, { params: Promise.resolve(params) }),
  { source: 'chatbot.agent.[runId].DELETE', requireAuth: true }
);

import { type NextRequest, NextResponse } from 'next/server';

import { getAgentBrowserSnapshotDelegate } from '@/features/ai/agent-runtime/store-delegates';
import type {
  AgentBrowserSnapshotRecord,
  AgentBrowserSnapshotsResponse,
} from '@/shared/contracts/agent-runtime';
import { internalError } from '@/shared/errors/app-error';
import {
  apiHandlerWithParams,
  type ApiHandlerContext as _ApiHandlerContext,
} from '@/shared/lib/api/api-handler';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

const DEBUG_CHATBOT = process.env['DEBUG_CHATBOT'] === 'true';

type AgentBrowserSnapshotRouteRecord = {
  id: string;
  runId: string;
  url: string;
  title: string | null;
  domHtml: string;
  domText: string;
  screenshotData: string | null;
  screenshotPath: string | null;
  stepId: string | null;
  mouseX: number | null;
  mouseY: number | null;
  viewportWidth: number | null;
  viewportHeight: number | null;
  createdAt: Date | string;
};

async function getHandler(
  req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const requestStart = Date.now();
  const agentBrowserSnapshot = getAgentBrowserSnapshotDelegate();
  if (!agentBrowserSnapshot) {
    throw internalError('Agent snapshot storage is unavailable.');
  }
  const { runId } = await params;
  const url = new URL(req.url);
  const stepId = url.searchParams.get('stepId');
  const limit = Number(url.searchParams.get('limit') ?? '12');
  const take = Number.isFinite(limit) ? Math.min(Math.max(limit, 1), 50) : 12;
  const snapshots = await agentBrowserSnapshot.findMany<AgentBrowserSnapshotRouteRecord>({
    where: { runId, ...(stepId ? { stepId } : {}) },
    orderBy: { createdAt: 'desc' },
    take,
  });
  if (DEBUG_CHATBOT) {
    void ErrorSystem.logInfo('Snapshots loaded', {
      service: 'agent-api',
      runId,
      count: snapshots.length,
      durationMs: Date.now() - requestStart,
    });
  }
  const response: AgentBrowserSnapshotsResponse = {
    snapshots: snapshots.map(
      (snapshot: AgentBrowserSnapshotRouteRecord): AgentBrowserSnapshotRecord => ({
        ...snapshot,
        title: snapshot.title ?? null,
        screenshotData: snapshot.screenshotData ?? null,
        screenshotPath: snapshot.screenshotPath ?? null,
        stepId: snapshot.stepId ?? null,
        mouseX: snapshot.mouseX ?? null,
        mouseY: snapshot.mouseY ?? null,
        viewportWidth: snapshot.viewportWidth ?? null,
        viewportHeight: snapshot.viewportHeight ?? null,
        createdAt:
          snapshot.createdAt instanceof Date ? snapshot.createdAt.toISOString() : snapshot.createdAt,
      })
    ),
  };
  return NextResponse.json(response);
}

export const GET = apiHandlerWithParams<{ runId: string }>(
  async (req: NextRequest, _ctx, params) => getHandler(req, { params: Promise.resolve(params) }),
  { source: 'chatbot.agent.[runId].snapshots.GET', requireAuth: true }
);

import { type NextRequest } from 'next/server';

import { getAgentBrowserSnapshotDelegate } from '@/features/ai/agent-runtime/store-delegates';
import { internalError } from '@/shared/errors/app-error';
import {
  apiHandlerWithParams,
  type ApiHandlerContext as _ApiHandlerContext,
} from '@/shared/lib/api/api-handler';
import { startIntervalTask, type IntervalTaskHandle } from '@/shared/lib/timers';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

const DEBUG_CHATBOT = process.env['DEBUG_CHATBOT'] === 'true';

async function getHandler(
  req: NextRequest,
  { params }: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const agentBrowserSnapshot = getAgentBrowserSnapshotDelegate();
  if (!agentBrowserSnapshot) {
    throw internalError('Agent snapshots not initialized.');
  }
  const { runId } = await params;
  const encoder = new TextEncoder();
  let timer: IntervalTaskHandle | null = null;

  const stream = new ReadableStream({
    async start(controller: ReadableStreamDefaultController) {
      const sendSnapshot = async () => {
        try {
          const latest = await agentBrowserSnapshot.findFirst({
            where: { runId },
            orderBy: { createdAt: 'desc' },
          });
          const payload = latest ? { snapshot: latest } : { snapshot: null };
          controller.enqueue(encoder.encode(`data: ${JSON.stringify(payload)}\n\n`));
        } catch (error) {
          logClientError(error);
          try {
            const { ErrorSystem } = await import('@/shared/lib/observability/system-logger');
            void ErrorSystem.captureException(error, {
              service: 'agent-stream',
              action: 'sendSnapshot',
              runId,
            });
          } catch (logError) {
            logClientError(logError);
            if (DEBUG_CHATBOT) {
              const { logger } = await import('@/shared/utils/logger');
              logger.error(
                '[chatbot][agent][stream] Snapshot fetch failed (and logging failed)',
                logError,
                {
                  runId,
                  error,
                }
              );
            }
          }
          controller.enqueue(
            encoder.encode(`data: ${JSON.stringify({ snapshot: null, error: 'snapshot' })}\n\n`)
          );
        }
      };

      await sendSnapshot();
      timer = startIntervalTask(() => {
        void sendSnapshot();
      }, 2000);

      req.signal.addEventListener('abort', () => {
        if (timer) {
          timer.cancel();
        }
        controller.close();
      });
